import React, { useEffect, useState } from 'react';
import { getMyTasks, updateTask, submitTask } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { format, isPast } from 'date-fns';

export default function MyTasks() {
  const { user } = useAuth();
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [selected, setSelected] = useState(null);
  const [submissionNote, setSubmissionNote] = useState('');

  useEffect(() => {
    getMyTasks()
      .then(res => setTasks(res.data.tasks))
      .catch(() => toast.error('Failed'))
      .finally(() => setLoading(false));
  }, []);

  const handleStart = async (id) => {
    try {
      const res = await updateTask(id, { status: 'in-progress' });
      setTasks(tasks.map(t => t._id === id ? res.data.task : t));
      toast.success('Task started!');
    } catch { toast.error('Failed'); }
  };

  const handleSubmit = async (id) => {
    try {
      const res = await submitTask(id, { submissionNote });
      setTasks(tasks.map(t => t._id === id ? res.data.task : t));
      setSelected(null);
      setSubmissionNote('');
      toast.success('Task submitted!');
    } catch { toast.error('Failed'); }
  };

  const filtered = tasks.filter(t => filter === 'all' ? true : t.status === filter);

  if (loading) return <div style={{textAlign:'center',padding:'60px',color:'#fff'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',padding:'30px',background:'linear-gradient(135deg,#0f172a,#022c22)'}}>

      {/* HEADER */}
      <div style={{marginBottom:'25px'}}>
        <h1 style={{fontSize:'32px',color:'#4ade80'}}>My Tasks</h1>
        <p style={{color:'#bbf7d0'}}>Tasks assigned to you</p>
      </div>

      {/* FILTER */}
      <div style={{display:'flex',gap:'10px',marginBottom:'25px',flexWrap:'wrap'}}>
        {['all','todo','in-progress','review','completed'].map(s => (
          <button
            key={s}
            onClick={() => setFilter(s)}
            style={{
              padding:'8px 14px',
              borderRadius:'8px',
              border:'none',
              cursor:'pointer',
              background: filter === s ? '#22c55e' : 'rgba(255,255,255,0.1)',
              color: filter === s ? '#022c22' : '#bbf7d0',
              fontSize:'13px'
            }}
          >
            {s}
          </button>
        ))}
      </div>

      {/* TASK LIST */}
      {filtered.length === 0 ? (
        <p style={{textAlign:'center',color:'#9ca3af'}}>No tasks</p>
      ) : (
        <div style={{display:'flex',flexDirection:'column',gap:'15px'}}>
          {filtered.map(task => {

            const isOverdue = task.deadline && isPast(new Date(task.deadline)) && task.status !== 'completed';

            return (
              <div key={task._id} style={{
                background:'rgba(255,255,255,0.06)',
                padding:'18px',
                borderRadius:'12px',
                border:'1px solid rgba(255,255,255,0.1)'
              }}>

                {/* TOP */}
                <div style={{display:'flex',justifyContent:'space-between',flexWrap:'wrap',gap:'10px'}}>

                  <div>
                    <div style={{fontSize:'16px',fontWeight:'600',color:'#fff'}}>
                      {task.title}
                    </div>

                    {task.description && (
                      <div style={{fontSize:'13px',color:'#9ca3af',marginTop:'4px'}}>
                        {task.description}
                      </div>
                    )}

                    <div style={{fontSize:'12px',marginTop:'6px',color:'#bbf7d0'}}>
                      📁 {task.project?.name}
                    </div>

                    {task.deadline && (
                      <div style={{fontSize:'12px',color:isOverdue ? '#f87171' : '#9ca3af'}}>
                        📅 {format(new Date(task.deadline),'MMM dd, yyyy')}
                      </div>
                    )}
                  </div>

                  {/* STATUS */}
                  <div style={{textAlign:'right'}}>
                    {isOverdue && <div style={{color:'#f87171',fontSize:'12px'}}>Overdue</div>}
                    <div style={{
                      marginTop:'5px',
                      padding:'4px 10px',
                      background:'#1f2937',
                      borderRadius:'6px',
                      fontSize:'12px',
                      color:'#e5e7eb'
                    }}>
                      {task.status}
                    </div>
                  </div>

                </div>

                {/* ACTIONS */}
                <div style={{marginTop:'12px',display:'flex',gap:'10px',flexWrap:'wrap'}}>

                  {task.status === 'todo' && (
                    <button onClick={() => handleStart(task._id)}
                      style={{padding:'6px 12px',background:'#22c55e',border:'none',borderRadius:'6px',color:'#022c22'}}>
                      Start
                    </button>
                  )}

                  {task.status === 'in-progress' && (
                    <button onClick={() => setSelected(task._id)}
                      style={{padding:'6px 12px',background:'#4ade80',border:'none',borderRadius:'6px',color:'#022c22'}}>
                      Submit
                    </button>
                  )}

                  {task.status === 'review' && (
                    <span style={{fontSize:'12px',color:'#eab308'}}>Waiting for review</span>
                  )}

                  {task.status === 'completed' && (
                    <span style={{fontSize:'12px',color:'#4ade80'}}>Completed</span>
                  )}

                </div>

                {/* SUBMIT BOX */}
                {selected === task._id && (
                  <div style={{marginTop:'12px'}}>
                    <textarea
                      rows={2}
                      placeholder="Write note..."
                      value={submissionNote}
                      onChange={e => setSubmissionNote(e.target.value)}
                      style={{
                        width:'100%',
                        padding:'8px',
                        borderRadius:'6px',
                        border:'1px solid rgba(255,255,255,0.2)',
                        background:'rgba(0,0,0,0.3)',
                        color:'#fff'
                      }}
                    />

                    <div style={{marginTop:'8px',display:'flex',gap:'8px'}}>
                      <button onClick={() => handleSubmit(task._id)}
                        style={{padding:'6px 12px',background:'#22c55e',border:'none',borderRadius:'6px',color:'#022c22'}}>
                        Confirm
                      </button>

                      <button onClick={() => setSelected(null)}
                        style={{padding:'6px 12px',background:'#374151',border:'none',borderRadius:'6px',color:'#fff'}}>
                        Cancel
                      </button>
                    </div>
                  </div>
                )}

              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
